-- INSERT MCQS
INSERT INTO mcqs (subject_id, topic_id, paper_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, reference_book) 
SELECT s.id, t.id, 1, 'Which drug is contraindicated in pregnancy due to its high risk of causing neural tube defects?', 'Warfarin', 'Valproic acid', 'Folic acid', 'Magnesium sulfate', 'B', 'Valproic acid is teratogenic and associated with neural tube defects. Warfarin is also teratogenic but causes bone and CNS abnormalities. Folic acid is protective. Magnesium sulfate is safe.', 'hard', 'Dewhurst  '
FROM subjects s
JOIN topics t ON t.subject_id = s.id
WHERE s.name = 'Gynaecology and Obstetrics' AND t.name = 'Drugs in Pregnancy';
INSERT INTO mcqs (subject_id, topic_id, paper_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, reference_book) 
SELECT s.id, t.id, 1, 'Which of the following drugs is most commonly associated with fetal hydantoin syndrome when used during pregnancy?', 'Phenytoin', 'Carbamazepine', 'Phenobarbital', 'Ethosuximide', 'A', 'Phenytoin causes fetal hydantoin syndrome characterized by craniofacial abnormalities, limb defects, and growth retardation.', 'medium', 'Ten Teachers  '
FROM subjects s
JOIN topics t ON t.subject_id = s.id
WHERE s.name = 'Gynaecology and Obstetrics' AND t.name = 'Teratogenicity';
INSERT INTO mcqs (subject_id, topic_id, paper_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, reference_book) 
SELECT s.id, t.id, 1, 'What is the primary mechanism of action of oxytocin in inducing labor?', 'Blocking progesterone receptors', 'Stimulating uterine smooth muscle contractions by increasing intracellular calcium levels', 'Antagonism of beta-2 adrenergic receptors', 'Inhibition of prostaglandin synthesis', 'B', 'Oxytocin stimulates uterine smooth muscle contractions by increasing intracellular calcium, promoting labor.', 'easy', 'Dewhurst  '
FROM subjects s
JOIN topics t ON t.subject_id = s.id
WHERE s.name = 'Gynaecology and Obstetrics' AND t.name = 'Oxytocics';
INSERT INTO mcqs (subject_id, topic_id, paper_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation, difficulty, reference_book) 
SELECT s.id, t.id, 1, 'Which antihypertensive drug is considered safe to use in pregnancy?', 'Enalapril', 'Labetalol', 'Losartan', 'Methyldopa', 'D', 'Methyldopa is safe and commonly used for hypertension in pregnancy. Enalapril and Losartan are contraindicated due to fetal renal damage. Labetalol is also used, but methyldopa is preferred in many guidelines.', 'medium', 'Ten Teachers  '
FROM subjects s
JOIN topics t ON t.subject_id = s.id
WHERE s.name = 'Gynaecology and Obstetrics' AND t.name = 'Drugs in Pregnancy';
